$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force -Path $directory | Out-Null

  if (Test-Path -LiteralPath $target) {
    $backup = $target + ".backup-auditoria-" + (Get-Date -Format "yyyyMMddHHmmss")
    Copy-Item -LiteralPath $target -Destination $backup -Force
    Write-Host "Backup: $backup" -ForegroundColor DarkYellow
  }

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)

  Write-Host "Atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "app\painel\layout.tsx" @"

"@

Write-Base64File "app\painel\page.tsx" @"

"@

# Remove entulho de instaladores e arquivo vazio acidental na raiz.
$removeList = @(
  "instalar-configuracoes-sem-uuid-undefined.ps1",
  "instalar-propostas-aprovacao-v6-orcaly.ps1",
  "instalar-v7.ps1",
  "sql-fix-admin-compatibilidade.sql",
  "grafica-flash"
)

foreach ($item in $removeList) {
  $path = Join-Path $project $item
  if (Test-Path -LiteralPath $path) {
    Remove-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue
    Write-Host "Removido: $item" -ForegroundColor Yellow
  }
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Ajustes de auditoria aplicados." -ForegroundColor Green
Write-Host "Corrigido: funcionários agora passam pelo /painel/layout.tsx." -ForegroundColor Cyan
Write-Host "Corrigido: link quebrado /painel/gerar-proposta -> /painel/propostas." -ForegroundColor Cyan
Write-Host "Adicionado: card de Produção no painel." -ForegroundColor Cyan
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
